namespace sv_ed6f83b49aa040a298ac216b1d92a49f.Services;

public class WarehouseInfo
{
    public string Id { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
}

/// <summary>
/// Scoped service holding the currently selected warehouse.
/// All interactive components in the same circuit share this instance.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A" },
        new() { Id = "WH-B", Name = "Warehouse B" },
        new() { Id = "WH-C", Name = "Warehouse C" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.FirstOrDefault(w => w.Id == _currentWarehouseId)?.Name
        ?? _currentWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId)
            return;

        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_ed6f83b49aa040a298ac216b1d92a49f.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts for the current warehouse.
/// Components subscribe to OnAlertCountChanged to react when polling detects new data.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int CurrentAlertCount { get; private set; }

    public event Action? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query returning low-stock item count for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Updates the cached count and notifies all subscribers.
    /// Called by the polling component after fetching new data.
    /// </summary>
    public void UpdateAlertCount(int newCount)
    {
        CurrentAlertCount = newCount;
        OnAlertCountChanged?.Invoke();
    }
}

