@rendermode InteractiveServer
@inject Services.WarehouseState Warehouse
@inject Services.InventoryAlertService AlertService
@implements IDisposable

<select class="form-select form-select-sm" style="width: 200px;"
        value="@Warehouse.CurrentWarehouseId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in Services.WarehouseState.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var warehouseId = e.Value?.ToString() ?? string.Empty;
        Warehouse.SetWarehouse(warehouseId);

        // Immediately fetch alert count for the new warehouse so all
        // subscribers see a fresh value without waiting for the next poll.
        var count = await AlertService.GetLowStockCountAsync(warehouseId);
        AlertService.UpdateAlertCount(count);
    }

    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        Warehouse.OnChange += _handler;
    }

    public void Dispose()
    {
        Warehouse.OnChange -= _handler;
    }
}

@rendermode InteractiveServer
@inject Services.InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-2">@AlertService.CurrentAlertCount</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _handler;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@inject Services.WarehouseState Warehouse
@inject Services.InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @Warehouse.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">@Warehouse.CurrentWarehouseName</h5>
        <p class="card-text">
            Low-stock alerts:
            <span class="badge @(AlertService.CurrentAlertCount > 0 ? "bg-danger" : "bg-success") fs-5">
                @AlertService.CurrentAlertCount
            </span>
        </p>
        <p class="text-muted small mb-0">
            Polling every 10 seconds. Last checked: @_lastChecked?.ToString("T")
        </p>
    </div>
</div>

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private DateTime? _lastChecked;
    private Action? _alertHandler;
    private Action? _warehouseHandler;

    protected override void OnInitialized()
    {
        // Subscribe to alert changes so this component re-renders
        // even when another component triggers an update.
        _alertHandler = () => InvokeAsync(() =>
        {
            _lastChecked = DateTime.Now;
            StateHasChanged();
        });
        AlertService.OnAlertCountChanged += _alertHandler;

        // Re-render when warehouse changes (selector triggers immediate fetch).
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        Warehouse.OnChange += _warehouseHandler;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            // Fetch immediately on load, then start polling.
            await PollAsync();
            StartPolling();
        }
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken cancellationToken)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(cancellationToken))
            {
                await PollAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose.
        }
    }

    private async Task PollAsync()
    {
        var count = await AlertService.GetLowStockCountAsync(Warehouse.CurrentWarehouseId);
        // UpdateAlertCount fires OnAlertCountChanged, which re-renders
        // ALL subscribed components (sidebar badge, this page, etc.).
        AlertService.UpdateAlertCount(count);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _alertHandler;
        Warehouse.OnChange -= _warehouseHandler;
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
    }
}

